#include <stdio.h>
#include <stdlib.h>

typedef struct {int val; int idx;} Pair;
int cmp(const void *a, const void *b) {
    Pair *p = (Pair *)a, *q = (Pair *)b;
    if (p->val != q->val) return q->val - p->val; // descending value
    return p->idx - q->idx; // ascending index
}
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        Pair *arr = (Pair*)malloc(N * sizeof(Pair));
        for(int i=0;i<N;i++){
            scanf("%d", &arr[i].val);
            arr[i].idx = i;
        }
        qsort(arr, N, sizeof(Pair), cmp);
        int *ans = (int*)malloc(N * sizeof(int));
        for(int i=0;i<N;i++) ans[arr[i].idx] = i+1;
        for(int i=0;i<N;i++){
            if(i) printf(" ");
            printf("%d", ans[i]);
        }
        printf("\n");
        free(arr); free(ans);
    }
    return 0;
}

