import java.io.*;
import java.util.*;

public class Main {
    static class Pair {
        int val;
        int idx;
        Pair(int v, int i){val=v; idx=i;}
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            st = new StringTokenizer(br.readLine());
            Pair[] arr = new Pair[N];
            for (int i = 0; i < N; i++) {
                int val = Integer.parseInt(st.nextToken());
                arr[i] = new Pair(val, i);
            }
            Arrays.sort(arr, (a, b) -> {
                if (a.val != b.val) return b.val - a.val; // descending
                return a.idx - b.idx; // ascending index
            });
            int[] ans = new int[N];
            for (int i = 0; i < N; i++) ans[arr[i].idx] = i + 1;
            for (int i = 0; i < N; i++) {
                if (i > 0) out.append(' ');
                out.append(ans[i]);
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

