const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  let pairs = new Array(N);
  for (let i = 0; i < N; i++) {
    const val = Number(input[idx++]);
    pairs[i] = {val: val, idx: i};
  }
  pairs.sort((a, b) => {
    if (a.val !== b.val) return b.val - a.val; // descending value
    return a.idx - b.idx; // ascending index
  });
  const ans = new Array(N);
  for (let i = 0; i < N; i++) {
    ans[pairs[i].idx] = i + 1;
  }
  outputs.push(ans.join(' '));
}
